# progress 파일 업데이트
with open('data/ocr-progress.json', 'r', encoding='utf-8') as f:
    progress = json.load(f)

for r in agent_results:
    code = r['code']
    progress[code] = {'question_text': r['q'], 'choice_1': r['c1'], 'choice_2': r['c2'], 'choice_3': r['c3'], 'choice_4': r['c4'], 'cost': 0}

with open('data/ocr-progress.json', 'w', encoding='utf-8') as f:
    json.dump(progress, f, ensure_ascii=False)

print(f'에이전트 결과 {len(agent_results)}개 저장')

# 아직 미처리된 항목 확인
with open('data/ocr-remaining.json', 'r', encoding='utf-8') as f:
    remaining = json.load(f)

still_missing = [q['code'] for q in remaining if q['code'] not in progress]
print(f'여전히 미처리: {len(still_missing)}개')
for c in still_missing:
    print(f'  {c}')
